import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { contentApi } from '../../services/api';
import ContentTable from '../../components/admin/ContentTable';
import '../Admin.css';

export default function AdminVideos() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState('');

  const loadVideos = () => {
    contentApi
      .getAll({ type: 'video' })
      .then(setVideos)
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    loadVideos();
  }, []);

  const showMessage = (text) => {
    setMessage(text);
    setTimeout(() => setMessage(''), 3000);
  };

  const handleToggle = async (id, field) => {
    try {
      const updated = await contentApi.toggle(id, field);
      setVideos((prev) => prev.map((v) => (v.id === id ? updated : v)));
      showMessage(`${field} updated for "${updated.title}"`);
    } catch (err) {
      showMessage(err.message);
    }
  };

  const handleDelete = async (id, title) => {
    if (!window.confirm(`Delete video "${title}"?`)) return;
    try {
      await contentApi.delete(id);
      setVideos((prev) => prev.filter((v) => v.id !== id));
      showMessage('Video deleted');
    } catch (err) {
      showMessage(err.message);
    }
  };

  return (
    <div className="dash-page">
      <div className="dash-page__header">
        <div>
          <h1>Videos</h1>
          <p>Manage all video content — toggle featured & trending status</p>
        </div>
        <Link to="/admin/videos/upload" className="btn btn-primary">
          + Upload Video
        </Link>
      </div>

      {message && <div className="dash-toast">{message}</div>}

      {loading ? (
        <div className="page-loading">Loading videos...</div>
      ) : (
        <ContentTable
          items={videos}
          onToggle={handleToggle}
          onDelete={handleDelete}
          emptyMessage="No videos yet. Upload your first video."
        />
      )}
    </div>
  );
}
